  ('heelevel3-6f0ba476-moex-00292', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列何者並非執行業務所得？', '["法人股東派員擔任董監事，法人所具領之車馬費、董監事酬勞", "執業會計師代理公司申請復查所收取之費用", "在臺灣拍攝、剪輯影片、上傳影片之個人Youtuber，接獲廠商業配合作之所得", "個人仲介透過不動產買賣收取的仲介報酬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00293', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列何者非屬可列舉扣除項目？', '["候選人競選經費之支出", "災害損失", "財產交易損失", "房屋租金支出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00294', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', 'A公司非金融業者，t-1期期初，備抵呆帳餘額為300,000元；t-1期期末，應收帳款與應收票據餘額 分別為15,000,000元與25,000,000元。t期內，實際發生呆帳800,000元；t期期末，應收帳款與應收 票據餘額分別為10,000,000元與20,000,000元。t期期末應提列呆帳金額為何？', '["300,000元", "400,000元", "700,000元", "800,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00295', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列有關營利事業房屋、土地交易所得課稅之敘述，何者錯誤？', '["總機構在中華民國境內之營利事業，持有房屋、土地之期間超過5年者，稅率為20%", "依土地稅法規定繳納之土地增值稅，不得列為成本費用", "當年度房屋、土地交易損失，應先自當年度適用相同稅率之房屋、土地交易所得中減除", "獨資、合夥組織營利事業之房屋、土地交易所得額，不計入獨資、合夥組織營利事業之所得額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00296', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列有關營利事業所得額計算之敘述，何者錯誤？', '["所得額之計算，涉有應稅所得及免稅所得者，其相關之成本、費用或損失，除可直接合理明確 歸屬者，得個別歸屬認列外，應作合理之分攤", "營利事業持有之短期票券發票日在中華民國99年1月1日以後者，其利息所得除依規定扣繳稅款 外，不計入營利事業所得額", "營利事業帳載應付未付之帳款、費用、損失及其他各項債務，逾請求權時效尚未給付者，應於 時效消滅年度轉列其他收入，俟實際給付時，再以營業外支出列帳", "營利事業所得之計算，以其年度收入總額減除各項成本費用、損失及稅捐後之純益額為所得額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00297', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '車商以65萬元向個人購入舊乘人小汽車一輛後，整修時因施工不慎，造成內裝瑕疵，乃以60萬元 （不含銷項稅額）降價售出。營業人於申報該輛舊乘人小汽車銷售額之當期，得扣抵之進項稅額 上限為何？', '["28,571元", "30,000元", "30,952元", "32,500元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00298', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '彩色電視機進口關稅稅率為10%（第一欄稅率，適用於世界貿易組織會員，或與我國有互惠國家 或地區），貨物稅稅率為13%；Ａ家電公司進口液晶電視，關稅完稅價格為50,000元，應納貨物稅 為多少元？', '["4,545元", "5,752元", "6,500元", "7,150元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00299', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '某丁為設籍高雄市之中華民國國民。102年5月，因病於美國馬里蘭州巴爾的摩郡住所去世；死亡 前2年內，在境內居留時間僅有30天。下列有關其遺產稅課稅之敘述，何者正確？', '["死亡地不在境內，不須繳納遺產稅", "就死亡時在境內之遺產，課徵遺產稅", "就死亡時在境外之遺產，課徵遺產稅", "就死亡時在境內外之全部遺產，課徵遺產稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00300', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '甲於112年5月間代理其子乙與出賣人丙簽訂土地買賣契約；土地公告現值為1,655萬7,600元，買賣 總價款為5,698萬元。因乙資金不夠，甲自銀行帳戶提領900萬元轉存乙同銀行帳戶，嗣乙開立支 票給付土地價款，該土地並登記為乙所有。經查乙給付土地價款之資金來源其中900萬元確實來自 甲，又甲無法提供相關文件證實其與乙之間有借貸關係存在，根據遺產及贈與稅法規定，應核定 贈與總額為何？（財政部公告112年發生之贈與案件適用之免稅額為244萬元。）', '["17萬5,276元", "261萬5,276元", "656萬元", "900萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00301', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列關於重新規定地價與申報地價之敘述，何者正確？', '["規定地價後，每3年重新規定地價一次", "土地所有權人於公告期間申報地價者，其申報之地價超過公告地價120%時，以公告地價120% 為其申報地價", "公告及申報地價，其期限為40日", "土地所有權人未於公告期間申報地價者，以公告地價為其申報地價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "83590898719d", "answer_pdf_sha1": "cb83a0f12e7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
